3. A specific example where text ends up in the wrong position?  

The devil is in the details with OT composition!

**Ah! Dependency cycles with three concurrent operations!** That's a really interesting edge case. This is likely a **transformation triangle inequality** violation. When you have ops A, B, C that form a cycle (A→B→C where C conflicts with A), the transformed results might not converge properly.

## 🔍 **The Triangle Problem in OT:**

For operations A, B, C where:
- A and B are concurrent
- B and C are concurrent  
- A and C are concurrent (forming a triangle)

You need: `transform(transform(A, B), transform(C, B')) == transform(transform(A, C), transform(B, C'))`
Where `B' = transform(B, A)` and `C' = transform(C, A)`

### **Common Bug Patterns with Cycles:**

### 1. **Missing "Re-transformation" after First Transformation**

```javascript
// Wrong: Transforming along one path only
function transformCycle(A, B, C) {
  const B_prime = transform(B, A);
  const C_prime = transform(C, A);
  const C_double_prime = transform(C_prime, B_prime);
  // ❌ This is path A→B→C, but what about A→C→B?
}
```

**Fix: Need convergence check:**
```javascript
function ensureConvergence(A, B, C) {
  // Path 1: A→B→C
  const B1 = transform(B, A);
  const C1 = transform(C, A);
  const C_final1 = transform(C1, B1);

  // Path 2: A→C→B  
  const C2 = transform(C, A);
  const B2 = transform(B, A);
  const B_final2 = transform(B2, C2);

  // They should converge to same state
  if (!operationsEquivalent(C_final1, B_final2)) {
    // Need to re-transform or resolve divergence
    return resolveDivergence(A, B, C);
  }

  return C_final1;
}
```

### 2. **Timestamp vs Vector Clock Cycle Resolution**

With Lamport timestamps, cycles can happen when:
- Client 1: generates A(t=10), receives B(t=9) → transforms A against B
- Client 2: generates B(t=9), receives A(t=10) → transforms B against A  
- Client 3: sees both transformed versions

**The bug often manifests as position double-counting:**
```javascript
// Example scenario
A = insert("X", pos=5)
B = insert("Y", pos=5)  // Same position!
C = delete(pos=5, length=1)

// Depending on transformation order:
// Path A→B→C: X inserted, Y inserted at pos=5, delete pos=5 → deletes X
// Path A→C→B: X inserted, delete pos=5 → deletes X, Y inserted at pos=5 → Y survives
// Different results!
```

## 🛠️ **Debugging Cycle-Specific Issues:**

### 1. **Add Cycle Detection and Logging:**

```javascript
class CycleDetector {
  constructor() {
    this.operationGraph = new Map(); // opId -> {deps: Set, timestamp}
    this.cyclesDetected = [];
  }

  trackOperation(opId, deps) {
    this.operationGraph.set(opId, {
      deps: new Set(deps),
      timestamp: Date.now()
    });

    // Check for cycles
    const cycle = this.findCycle(opId);
    if (cycle) {
      console.error('CYCLE DETECTED:', cycle);
      this.cyclesDetected.push({
        cycle,
        operations: cycle.map(id => this.getOperation(id)),
        timestamp: Date.now()
      });
      return cycle;
    }
    return null;
  }

  findCycle(startId, visited = new Set(), path = []) {
    visited.add(startId);
    path.push(startId);

    const node = this.operationGraph.get(startId);
    if (node) {
      for (const depId of node.deps) {
        if (path.includes(depId)) {
          // Cycle found
          const cycleStart = path.indexOf(depId);
          return path.slice(cycleStart);
        }
        if (!visited.has(depId)) {
          const cycle = this.findCycle(depId, visited, path);
          if (cycle) return cycle;
        }
      }
    }

    path.pop();
    return null;
  }
}
```

### 2. **3-Operation Convergence Test:**

```javascript
function testTriangleConvergence(A, B, C) {
  console.log('\n=== Testing Triangle Convergence ===');
  console.log('A:', A);
  console.log('B:', B);
  console.log('C:', C);

  // All 6 possible transformation orders
  const paths = [
    ['A→B→C', applyTransformOrder([A, B, C])],
    ['A→C→B', applyTransformOrder([A, C, B])],
    ['B→A→C', applyTransformOrder([B, A, C])],
    ['B→C→A', applyTransformOrder([B, C, A])],
    ['C→A→B', applyTransformOrder([C, A, B])],
    ['C→B→A', applyTransformOrder([C, B, A])]
  ];

  const results = new Set();
  paths.forEach(([name, result]) => {
    console.log(`${name}:`, result);
    results.add(JSON.stringify(result));
  });

  if (results.size > 1) {
    console.error('❌ NON-CONVERGENT TRIANGLE!');
    debugger;
    return false;
  }

  console.log('✅ All paths converge');
  return true;
}

function applyTransformOrder(ops) {
  let result = ops[0];
  let currentText = '';

  for (let i = 1; i < ops.length; i++) {
    currentText = applyOperation(currentText, result);
    result = transformOperation(ops[i], result);
  }

  return {
    finalOp: result,
    finalText: applyOperation(currentText, result)
  };
}
```

### 3. **Visualize the Transformation Diamond:**

```javascript
function visualizeTransformationDiamond(A, B, C) {
  /*
      A      B
       ↘    ↙
         AB
         ↓
        ABC
       ↙
      C

      vs

      A      C  
       ↘    ↙
         AC
         ↓
        ACB
       ↙
      B
  */

  const AB = transform(B, A);
  const AC = transform(C, A);
  const ABC_path1 = transform(C, AB);  // A→B→C path
  const ACB_path2 = transform(B, AC);  // A→C→B path

  const BA = transform(A, B);
  const BC = transform(C, B);
  const BAC_path3 = transform(C, BA);
  const BCA_path4 = transform(A, BC);

  console.log('Transformation Diamond:');
  console.log('Path A→B→C:', ABC_path1);
  console.log('Path A→C→B:', ACB_path2);
  console.log('Path B→A→C:', BAC_path3);
  console.log('Path B→C→A:', BCA_path4);

  // Check if all end states are equivalent
  const endStates = [
    applyOperation(applyOperation(applyOperation('', A), B), ABC_path1),
    applyOperation(applyOperation(applyOperation('', A), C), ACB_path2),
    applyOperation(applyOperation(applyOperation('', B), A), BAC_path3),
    applyOperation(applyOperation(applyOperation('', B), C), BCA_path4)
  ];

  return {
    converges: new Set(endStates).size === 1,
    endStates,
    transformationPaths: { ABC_path1, ACB_path2, BAC_path3, BCA_path4 }
  };
}
```

## 💡 **The Likely Fix: TP2 Algorithm Adaptation**

For 3-operation cycles, you might need TP2 (Transformation Property 2) checking:

```javascript
function checkTP2(A, B, C) {
  // TP2: transform(transform(A, B), transform(C, B')) == transform(transform(A, C), transform(B, C'))
  // Where B' = transform(B, A) and C' = transform(C, A)

  const B_prime = transform(B, A);
  const C_prime = transform(C, A);

  const leftSide = transform(transform(A, B), transform(C, B_prime));
  const rightSide = transform(transform(A, C), transform(B, C_prime));

  const tp2Holds = operationsEquivalent(leftSide, rightSide);

  if (!tp2Holds) {
    console.error('TP2 VIOLATION!');
    console.log('A:', A);
    console.log('B:', B);
    console.log('C:', C);
    console.log('B_prime:', B_prime);
    console.log('C_prime:', C_prime);
    console.log('Left:', leftSide);
    console.log('Right:', rightSide);

    // Apply convergence fix
    return enforceConvergence(A, B, C);
  }

  return leftSide;
}

function enforceConvergence(A, B, C) {
  // Choose operation with "dominant" timestamp or some deterministic rule
  const ops = [A, B, C];
  ops.sort((a, b) => {
    // Sort by timestamp, then client ID for deterministic ordering
    if (a.timestamp !== b.timestamp) return a.timestamp - b.timestamp;
    return a.clientId.localeCompare(b.clientId);
  });

  // Apply in deterministic order
  let result = ops[0];
  for (let i = 1; i < ops.length; i++) {
    result = transform(ops[i], result);
  }

  console.warn('Using deterministic fallback due to TP2 violation');
  return result;
}
```

