    let visibleCount = 0;
    for (const charId of this.rga.sequence) {
      const char = this.rga.characters.get(this.rga.keyFromId(charId));
      if (char && !char.tombstone) {
        if (visibleCount === position) {
          return char.parentId; // Insert AFTER this character's parent
        }
        visibleCount++;
      }
    }
    return null; // Insert at end
  }

  getCursorPosition(charId) {
    let position = 0;
    for (const id of this.rga.sequence) {
      const char = this.rga.characters.get(this.rga.keyFromId(id));
      if (char && !char.tombstone && this.rga.keyFromId(id) === this.rga.keyFromId(charId)) {
        return position;
      }
      if (char && !char.tombstone) {
        position++;
      }
    }
    return position;
