## 📐 **B-Tree Index for RGA Insertion Lookup:**

Here's a production-ready B-Tree index optimized for RGA's unique needs:

```javascript
class RGAIndex {
  constructor(fanout = 32) {
    this.root = new LeafNode();
    this.fanout = fanout; // B-Tree branching factor
    this.idToNode = new Map(); // charId -> node reference
    this.positionCache = new Map(); // charId -> [node, index]
    this.cacheHits = 0;
    this.cacheMisses = 0;
    this.rebuildThreshold = 10000;
  }

  // Key comparison for B-Tree ordering
  compareKeys(a, b) {
    // Vector clock comparison
    // Compare timestamps for each client
    const allClients = new Set([
      ...Object.keys(a.timestamps || {}),
      ...Object.keys(b.timestamps || {})
    ]);

    for (const client of allClients) {
      const aTs = a.timestamps?.[client] || 0;
      const bTs = b.timestamps?.[client] || 0;

      // Partial order: concurrent if neither dominates
      if (aTs > bTs && a.dominates?.(b)) return 1;
      if (bTs > aTs && b.dominates?.(a)) return -1;
    }

    // Tie-breaker: clientId
    return a.clientId.localeCompare(b.clientId);
  }

  // Insert with O(log n) lookup
  insert(charId, afterId = null) {
    let insertionNode;
    let insertionIndex;

    // Try cache first
    if (this.positionCache.has(afterId)) {
      this.cacheHits++;
      [insertionNode, insertionIndex] = this.positionCache.get(afterId);
      insertionIndex++; // Insert after this position
    } else {
      this.cacheMisses++;

      if (afterId === null) {
        // Insert at beginning - special case
        const [firstKey] = this.root.getFirstKey();
        return this.insertAtPosition(null, firstKey ? -1 : 0);
      }

      // Binary search through B-Tree
      const path = this.findPath(afterId);
      if (path.length === 0) {
        throw new Error(`Parent ${afterId} not found`);
      }

      [insertionNode, insertionIndex] = path[path.length - 1];
      insertionIndex++; // Need position AFTER the parent
    }

    // Perform insertion
    const newNode = insertionNode.insertAt(insertionIndex, charId);

    // Update cache
    this.positionCache.set(charId, [newNode, insertionIndex]);

    // If we inserted after an existing node, update following positions
    this.updateFollowingPositions(insertionNode, insertionIndex);

    // Split if needed
    if (newNode.keys.length > this.fanout) {
      this.splitNode(newNode);
    }

    // Periodic cache cleanup
    if (this.positionCache.size > this.rebuildThreshold) {
      this.rebuildCache();
    }

    return insertionIndex;
  }

  // B-Tree search with path recording
  findPath(targetId) {
    let node = this.root;
    const path = [];

    while (!node.isLeaf) {
      let index = 0;
      // Binary search within node keys
      let low = 0;
      let high = node.keys.length - 1;

      while (low <= high) {
        const mid = Math.floor((low + high) / 2);
        const cmp = this.compareKeys(targetId, node.keys[mid]);

        if (cmp === 0) {
          index = mid;
          break;
        } else if (cmp < 0) {
          high = mid - 1;
        } else {
          low = mid + 1;
          index = low;
        }
      }

      path.push([node, index]);
      node = node.children[index];
    }

    // Binary search in leaf node
    let low = 0;
    let high = node.keys.length - 1;
    let index = 0;

    while (low <= high) {
      const mid = Math.floor((low + high) / 2);
      const cmp = this.compareKeys(targetId, node.keys[mid]);

      if (cmp === 0) {
        index = mid;
        break;
      } else if (cmp < 0) {
        high = mid - 1;
      } else {
        low = mid + 1;
        index = low;
      }
    }

    path.push([node, index]);
    return path;
  }
}

// B-Tree Node implementations
class BTreeNode {
  constructor(isLeaf = true) {
    this.keys = [];
    this.children = [];
    this.isLeaf = isLeaf;
    this.next = null; // Linked list for leaf traversal
    this.prev = null;
  }

  insertAt(index, key) {
    this.keys.splice(index, 0, key);
    return this;
  }

  getFirstKey() {
    let node = this;
    while (!node.isLeaf) {
      node = node.children[0];
