  }

  // Get character ID at visual position (with tombstones filtered)
  getCharIdAtPosition(targetPos) {
    // Binary search through positionIndex
    let low = 0;
    let high = this.positionIndex.size - 1;

    while (low <= high) {
      const mid = Math.floor((low + high) / 2);
      const [charId, visible] = this.positionIndex.get(mid);

      if (!visible) {
        // Skip tombstones - need to adjust
        // This is the tricky part with tombstones
        return this.getCharIdAtPositionBinarySearch(targetPos);
      }

      const currentPos = this.charIdToPosition.get(charId);
      if (currentPos === targetPos) return charId;
      else if (currentPos < targetPos) low = mid + 1;
      else high = mid - 1;
    }

    return null;
  }

  getCharIdAtPositionBinarySearch(targetPos) {
    // Alternative: walk the B-Tree filtering tombstones
    let node = this.root;
    let currentPos = 0;

    while (node) {
      for (let i = 0; i < node.keys.length; i++) {
        const charId = node.keys[i];
        const char = this.characters.get(this.keyFromId(charId));

        if (!char.tombstone) {
          if (currentPos === targetPos) return charId;
          currentPos++;
        }
      }
      node = node.next;
    }

    return null;
  }
}
