class RGAFingerTree {
  constructor() {
    this.tree = new FingerTree();
    this.idToNode = new Map();
    this.positionCache = new LRU(1000);

    // "Finger" for nearby insertions
    this.leftFinger = { charId: null, node: null, position: 0 };
    this.rightFinger = { charId: null, node: null, position: 0 };
  }

  insert(charId, afterId) {
    // Check fingers first (common case: nearby edits)
    if (afterId === this.leftFinger.charId) {
      return this.insertAfterFinger(charId, this.leftFinger, 'left');
    }
    if (afterId === this.rightFinger.charId) {
      return this.insertAfterFinger(charId, this.rightFinger, 'right');
    }

    // Fall back to binary search
    return this.insertBinarySearch(charId, afterId);
  }

  insertAfterFinger(charId, finger, side) {
    const newNode = this.tree.insertAfter(finger.node, charId);
    this.idToNode.set(charId, newNode);

    // Update finger positions
    if (side === 'left') {
      this.leftFinger = { charId, node: newNode, position: finger.position + 1 };
    } else {
      this.rightFinger = { charId, node: newNode, position: finger.position + 1 };
    }

    this.updatePositionCache(newNode, finger.position + 1);

    return finger.position + 1;
  }
}
